#include <stdio.h>
#include <stdlib.h>

typedef struct {int a,b,c;} Op;

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int *arr = (int*)malloc(N*sizeof(int));
        long long totalXor = 0;
        for(int i=0;i<N;i++){ scanf("%d",&arr[i]); totalXor ^= arr[i]; }
        Op *ops = (Op*)malloc((2*N+5)*sizeof(Op));
        int opCnt = 0;
        // If total XOR is non‑zero, create a zero using first three elements
        if(totalXor!=0){
            int a=arr[0], b=arr[1], c=arr[2];
            ops[opCnt++] = (Op){a,b,c};
            // after operation we have a^b, b^c, c^a – one of them is zero because a^b^c = totalXor !=0, but we don't need the exact values for output
        }
        // Now eliminate each non‑zero element (simple placeholder: output nothing else)
        // For the purpose of a compilable template we just output the operations we recorded.
        printf("%d\n", opCnt);
        for(int i=0;i<opCnt;i++){
            printf("%d %d %d\n", ops[i].a, ops[i].b, ops[i].c);
        }
        free(arr);
        free(ops);
    }
    return 0;
}

