import java.io.*;
import java.util.*;

public class Main {
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){ this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
        int nextInt() throws IOException { return (int) nextLong(); }
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        StringBuilder out = new StringBuilder();
        int T = fs.nextInt();
        while (T-- > 0) {
            int N = fs.nextInt();
            long total = 0;
            long[] arr = new long[N];
            for (int i = 0; i < N; i++) { arr[i] = fs.nextLong(); total ^= arr[i]; }
            List<long[]> ops = new ArrayList<>();
            if (total != 0 && N >= 3) {
                ops.add(new long[]{arr[0], arr[1], arr[2]});
            }
            out.append(ops.size()).append('\n');
            for (long[] op : ops) {
                out.append(op[0]).append(' ').append(op[1]).append(' ').append(op[2]).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

