#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        total = 0
        for v in arr:
            total ^= v
        ops = []
        if total != 0 and N >= 3:
            ops.append((arr[0], arr[1], arr[2]))
        out_lines.append(str(len(ops)))
        for a,b,c in ops:
            out_lines.append(f"{a} {b} {c}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

